func TestRunGmailHistoryRefresh_ExpiredHistoryFallback(t *testing.T) {
	home := t.TempDir()
	t.Setenv("HOME", home)
	configPath, tokenStorePath := withConfigPath(t)
	writeConfigPointingAt(t, configPath, "http://unused", "user@example.com")
	storeFile := auth.NewStoreAt(tokenStorePath)
	now := time.Now().UnixMilli()
	if _, err := storeFile.Upsert("user@example.com", auth.AccountTokens{
		Type:        "google",
		AccessToken: "ya29.test",
		UserID:      "gid-001",
		SuperhumanToken: auth.SuperhumanToken{
			Token:   "id-token",
			Expires: now + int64(time.Hour.Milliseconds()),
		},
		LastUsedAt: now,
	}); err != nil {
		t.Fatalf("seed tokens: %v", err)
	}
	db, err := store.Open(filepath.Join(home, ".local", "share", "superhuman-pp-cli", "data.db"))
	if err != nil {
		t.Fatalf("open store: %v", err)
	}
	if err := db.SaveHistoryState(t.Context(), "user@example.com", "old", time.Now(), time.Now()); err != nil {
		t.Fatalf("save history: %v", err)
	}
	db.Close()

	requests := 0
	srv := httptest.NewServer(http.HandlerFunc(func(w http.ResponseWriter, r *http.Request) {
		requests++
		switch {
		case strings.HasPrefix(r.URL.Path, "/users/me/history"):
			http.Error(w, "Requested entity was not found.", http.StatusNotFound)
		case strings.HasPrefix(r.URL.Path, "/users/me/messages") && r.URL.Query().Get("format") == "":
			_, _ = w.Write([]byte(`{"messages":[]}`))
		default:
			http.Error(w, "unexpected "+r.URL.String(), http.StatusInternalServerError)
		}
	}))
	defer srv.Close()
	origBaseURL := gmail.BaseURL
	gmail.BaseURL = srv.URL
	t.Cleanup(func() { gmail.BaseURL = origBaseURL })

	flags := &rootFlags{configPath: configPath}
	cmd := &cobra.Command{Use: "threads"}
	result := runGmailHistoryRefresh(cmd, flags)
	if result.Err != nil {
		t.Fatalf("expired history fallback should succeed: %v", result.Err)
	}
	if result.Status != "ok" {
		t.Fatalf("status = %q want ok", result.Status)
	}
	if requests < 2 {
		t.Fatalf("expected history request plus fallback list requests, got %d", requests)
	}
}
